try:
    obj = json.loads(raw)
except json.JSONDecodeError:
    # `.exception` adds the active traceback automatically; only valid inside `except`.
    logger.exception("failed to parse LLM JSON response", extra={"raw_head": raw[:500]})
    return None
except Exception as e:
    # Outside the standard except chain — log with exc_info explicitly:
    logger.error("unexpected parse error: %s", e, exc_info=True)
    raise

import logging.config
import os

LOGGING = {
    "version": 1,
    "disable_existing_loggers": False,
    "formatters": {
        "plain": {"format": "%(asctime)s %(levelname)-8s %(name)s: %(message)s"},
        "json":  {"()": "pythonjsonlogger.jsonlogger.JsonFormatter",
                  "format": "%(asctime)s %(levelname)s %(name)s %(message)s"},
    },
    "handlers": {
        "console": {"class": "logging.StreamHandler", "formatter": "plain"},
        "jsonfile": {"class": "logging.handlers.RotatingFileHandler",
                     "filename": "app.log",
                     "maxBytes": 10_000_000,
                     "backupCount": 5,
                     "formatter": "json"},
    },
    "root": {
        "level": os.environ.get("LOG_LEVEL", "INFO"),
        "handlers": ["console", "jsonfile"],
    },
    "loggers": {
        "ragapp.retrieval": {"level": "DEBUG"},  # noisier sub-system
        "httpx":             {"level": "WARNING"},  # quiet vendor logger
    },
}

logging.config.dictConfig(LOGGING)
